import React, { useState, useEffect } from "react";
import "./App.css";

const TextSwapAnimation = ({ words, interval = 3000 }) => {
  const [index, setIndex] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setIndex((prevIndex) => (prevIndex + 1) % words.length);
    }, interval);
    return () => clearInterval(timer);
  }, [words, interval]);

  return <div className="text-swap-animation">{words[index]}</div>;
};

function App() {
  const words = ["Hello", "World", "React", "Animation"];
  return (
    <div className="App">
      <TextSwapAnimation words={words} />
    </div>
  );
}

export default App;
